const Q_ACCOUNTS_2024_MODEL_I=[{"id": "objective>Accounts>2024 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic accounting equation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Assets + Liabilities = Owner's Equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assets - Liabilities = Owner's Equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revenue - Expenses = Profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assets + Expenses = Liabilities + Equity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Assets + Liabilities = Owner's Equity.  This equation is the foundation of double-entry bookkeeping and ensures that a company's financial statements are balanced. Let's break down the equation: <br/>  <br/> Assets: These are the resources a company owns, such as cash, inventory, property, and equipment. <br/> Liabilities: These are the company's debts or financial obligations that need to be repaid. <br/> Owner's Equity (also called Shareholders' Equity): This represents the owners' claim on the company's assets after all liabilities are settled. It's essentially the difference between the company's assets and liabilities.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2024 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suppliers accounts are found in the ........................ ledger</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">general</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nominal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">private</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purchase ledger is a subsidiary ledger that records all transactions related to purchases made from suppliers on credit. Each supplier has a dedicated account in the purchase ledger.</div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2024 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A commission of #5000 to a sales manager was debited to debtors account. This is an error of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compensation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">original entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">principle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This type of error occurs when a fundamental accounting rule or concept is violated. In this case, debiting a commission (an expense) to the debtors account (an asset account) goes against the basic principles of double-entry bookkeeping. Debtors accounts represent money owed by customers, and commissions are not related to customer debts.</div>", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE"}, {"id": "objective>Accounts>2024 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short term solvency of a company is determined with  .......................... ratio</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acid test</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors to equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross profit margin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The acid-test ratio assesses a company's ability to meet its short-term obligations (due within a year) using its most liquid assets. It goes beyond the current ratio by excluding inventory from the calculation, as inventory might take longer to convert into cash to pay off debts.</div>", "topic": "ACCOUNTING RATIO :PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2024 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The return on debenture holding is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">share bonus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debentures are essentially loans that a company issues to investors. In return for investing in the debenture, the investor receives periodic interest payments at a predetermined rate. This interest is a fixed obligation of the company, regardless of its profitability.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2024 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount by which assets exceeds liabilities is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bonus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner's  equity (also known as shareholder's equity or capital) represents the remaining value that belongs to the company's owners after all liabilities are settled. It essentially reflects the net worth of the business from the owners' perspective.</div>", "topic": "ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2024 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of fictitious assets is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">goodwill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overdraft</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fictitious assets are intangible assets that  do not have a physical form and lack inherent value.  They represent deferred expenses or prepaid costs that provide benefits over future periods. For example: Preliminary Expenses, Discount on Issue of Shares, Goodwill etc.</div>", "topic": "GOODWILL ACCOUNTS : INTRODUCTION AND REASONS FOR GOODWILL"}, {"id": "objective>Accounts>2024 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost consist of direct material and ................... cost</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">factory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overhead</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost refers to the direct costs associated with producing a good. These are costs that can be easily traced and directly linked to each unit of production.  It consists of direct materials, direct labour and direct cost.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2024 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document used in making lodgments into a current account is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheque book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pass book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paying in -slip</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A paying-in slip, also sometimes called a deposit slip, is a crucial document used when making deposits into a current account, especially for cash and cheques.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>2024 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rent accrued at the end of an accounting period is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed asset</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rent accrued: This refers to the expense incurred for using an asset (property, equipment, etc.) for a period, even though the rent payment hasn't been made yet. <br/>  <br/> Current liability: A current liability is a short-term financial obligation that a company expects to settle within one year or the operating cycle (whichever is longer). Rent accrued falls under this category because it's a debt that needs to be paid to the landlord soon.</div>", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS"}, {"id": "objective>Accounts>2024 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A list of all debit and credit balances from the ledger accounts are made in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trial balance</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A trial balance is a worksheet that summarizes the ending balances of all ledger accounts after a specific accounting period. It lists each account title and its corresponding debit or credit balance.</div>", "topic": "TRIAL BALANCE : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2024 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The net worth of a business is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner's Equity/Capital is a term signifies the claim that the owners have on the company's net assets. It's essentially the difference between the company's assets and liabilities.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2024 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tolu purchased a machine for #6,000 on credit. The effect is to debit................... and credit the account of the supplier</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creditor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">machinery</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When Tolu purchases a machine on credit, the accounting entries reflect the following: <br/> Debit: Machinery  (#6,000) <br/> Credit: Supplier (#6,000) <br/>  <br/> Here's why: <br/> Debit: A debit increases an asset account. In this case, \"Machinery\" is an asset account that represents the new equipment Tolu acquired. <br/> Credit: A credit increases a liability account. Since Tolu purchases the machine on credit, they now owe money to the supplier. The \"Supplier\" account is a liability account that reflects this debt.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2024 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following balances were extracted from the books of Oluwalambe Ltd, a manufacturer, on 31st December 2007. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 80000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases of raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 450000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 31- 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 95000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages</td><td style=\"border:1px solid black;text-align:center;\"> 65000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation on plants</td><td style=\"border:1px solid black;text-align:center;\"> 32000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 32500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 31 - 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 37500</td></tr></table></div> <br/>  <br/> Cost of raw materials consumed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#425,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#435,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#450,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#499,500</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of Raw Materials Consumed = Opening Stock of Raw Materials + Purchases of Raw Materials - Closing Stock of Raw Materials <br/>  <br/> Cost of Raw Materials Consumed = #80,000 + #450,000 - #95,000 <br/>  <br/> Cost of Raw Materials Consumed = #435,000</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2024 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Oluwalambe Ltd, a manufacturer, on 31st December 2007. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 80000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases of raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 450000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 31- 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 95000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages</td><td style=\"border:1px solid black;text-align:center;\"> 65000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation on plants</td><td style=\"border:1px solid black;text-align:center;\"> 32000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 32500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 31 - 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 37500</td></tr></table></div> <br/> The prime cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#530,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#527,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#500,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#463,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime Cost = Direct Materials Cost + Direct Labor Cost <br/>  <br/> Direct Materials Cost (Cost of Raw Materials Consumed): We have already calculated this in the previous question and found it to be #435,000 <br/>  <br/> Prime Cost = #435,000 (Direct Materials) + #65,000 (Direct Labor) <br/>  <br/> Prime Cost = #500,000</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2024 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Oluwalambe Ltd, a manufacturer, on 31st December 2007. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 80000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases of raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 450000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 31- 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 95000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages</td><td style=\"border:1px solid black;text-align:center;\"> 65000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation on plants</td><td style=\"border:1px solid black;text-align:center;\"> 32000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 32500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 31 - 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 37500</td></tr></table></div> <br/> Factory overhead cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#12,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#58,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#63,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#68,500</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factory Overhead Cost = Indirect Wages + Depreciation on Plants + Factory Rent <br/>  <br/> Factory Overhead Cost = #28,000 + #32,000 + #3,500 <br/>  <br/> Factory Overhead Cost = #63,500</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2024 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Oluwalambe Ltd, a manufacturer, on 31st December 2007. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 80000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases of raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 450000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock of raw materials 31- 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 95000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct wages</td><td style=\"border:1px solid black;text-align:center;\"> 65000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 28000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation on plants</td><td style=\"border:1px solid black;text-align:center;\"> 32000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 1- 1- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 32500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Work in progress 31 - 12- 2007</td><td style=\"border:1px solid black;text-align:center;\"> 37500</td></tr></table></div> <br/> Cost of goods produced is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#520,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#530,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#559,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> #558,500</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of Goods Produced = Prime Cost + Factory Overhead Cost + Opening Work in Progress - Closing Work in Progress <br/>  <br/> Prime Cost: #500,000 (from previous question) <br/> Factory Overhead Cost: #63,500 (from previous question) <br/>  <br/> Cost of Goods Produced = #500,000 + #63,500 + #32,500 - #37,500 <br/>  <br/> Cost of Goods Produced =  #558,500</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2024 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chief accounting officer of the Federation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Accountant General</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Auditor General</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief Accountant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Minister of Economic Planning</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Accountant General of the Federation is the head of the Office of the Accountant General of the Federation (OAGF), which is the treasury of the Federal Republic of Nigeria. They are responsible for overseeing the government's receipts and payments, ensuring proper accounting practices, and managing the Federation Account.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}, {"id": "objective>Accounts>2024 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Issue of prospectus is an invitation to the Public to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquidate a company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redeem all outstanding shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">register a company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subscribe for shares</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A prospectus is a formal legal document that provides detailed information about a company's financial condition, its plans for the future, and the risks involved in investing. <br/> The primary purpose of issuing a prospectus is to attract potential investors to buy (subscribe for) shares of the company's stock.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2024 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of a device that can be used for input, storage, and output in a computer system?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Central processing unit (CPU)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">USB flash drive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Keyboard</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">USB flash drive:  In contrast to the other options, a USB flash drive can function in all three ways: <br/> Input: Data can be transferred from the flash drive to the computer's storage (e.g., copying files). <br/> Storage: The flash drive itself can store data portably. <br/> Output: Data stored on the flash drive can be accessed and displayed on the computer (e.g., opening documents).</div>", "topic": "INTRODUCTION TO DATA PROCESSING : MEANING, CLASSIFICATION AND COMPONENTS OF COMPUTER"}, {"id": "objective>Accounts>2024 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are over-subscribed, directors may decide to scale down the number of shareholding by alloting shares at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discount</div>", "<div style=\"font-family:Cambria;font-size:17px;\">par</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prorata</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This method distributes shares proportionally to the number of shares applied for by each investor. For example, if an investor applied for 100 shares and the overall subscription is 200% (twice the offered amount), they might receive a prorated allocation of 50 shares (100 shares requested / 2 (oversubscription factor) = 50 shares allocated).</div>", "topic": "ISSUES OF SHARES : SHARES PAYABLE IN FULL ON APPLICATIONS"}, {"id": "objective>Accounts>2024 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A public limited liability company can get additional fund through the issue of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accumulated fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidated fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Issuing debentures allows a PLC to raise capital from investors. Debentures are essentially loans provided by investors to the company. The company promises to repay the principal amount borrowed along with interest at a predetermined rate. Debenture holders are creditors of the company, ranking higher than shareholders in terms of claims on the company's assets in case of liquidation.</div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2024 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of accounts in the nominal ledger is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creditors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drawings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">machineries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nominal ledger, also sometimes called the general ledger, is the main book of accounts used in a double-entry bookkeeping system. It records all the financial transactions of a business during an accounting period. These transactions are categorized into different types of accounts.</div>", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER"}, {"id": "objective>Accounts>2024 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shares issued free of charge to existing shareholders based on their previous holdings is .......... issue</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accrued</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">floating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bonus issue is a way for a company to reward existing shareholders by distributing additional shares to them at no cost. The number of bonus shares received by each shareholder is typically proportional to their existing shareholding.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2024 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount paid by the buyer of a business which is sold as going concern is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conversion fees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidation fees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium fees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase consideration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Purchase consideration is the amount that's received by the vendor company (Seller) for the assets and liabilities takeover by the purchasing company in exchange for cash or in other forms, such as issuing shares or other securities.</div>", "topic": "PURCHASES OF BUSINESS : ENTRIES IN THE BOOK OF THE PURCHASER"}, {"id": "objective>Accounts>2024 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following balances were extracted from the books of Adama Ltd on 31st August 2007 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Furniture</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 85000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General expenses</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock ( 31-08-2007)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 140000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-09- 2006)</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td></tr></table></div> <br/>  <br/> Percentage of net profit to sale is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the Cost of Goods Sold (COGS): <br/> COGS = Opening Stock (1-09-2006) + Purchases - Closing Stock (31-08-2007) <br/> COGS = #20,000 + #140,000 - #10,000 <br/> COGS = #150,000 <br/>  <br/> Calculate the Gross Profit: <br/> Gross Profit = Sales - COGS <br/> Gross Profit = #200,000 - #150,000 <br/> Gross Profit = #50,000 <br/>  <br/> Calculate the Net Profit: <br/> Net Profit = Gross Profit - General Expenses <br/> Net Profit = #50,000 - #10,000 <br/> Net Profit = #40,000 <br/>  <br/> Calculate the Net Profit Percentage: <br/> Net Profit Percentage = (Net Profit / Sales) x 100 <br/> Net Profit Percentage = (#40,000 / #200,000) x 100 <br/> Net Profit Percentage =20 %</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2024 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Adama Ltd on 31st August 2007 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Furniture</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 85000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General expenses</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock ( 31-08-2007)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 140000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-09- 2006)</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td></tr></table></div> <br/> Total fixed assets is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#70,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#80,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#150,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#165,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total Fixed Assets = Land and Building + Furniture <br/>  <br/> Total Fixed Assets = #70,000 + #10,000 <br/>  <br/> Total Fixed Assets = #80,000</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2024 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Adama Ltd on 31st August 2007 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Furniture</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 85000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General expenses</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock ( 31-08-2007)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 140000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-09- 2006)</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td></tr></table></div> <br/> The gross profit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#40,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#60,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#70,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the Cost of Goods Sold (COGS): <br/> COGS = Opening Stock (1-09-2006) + Purchases - Closing Stock (31-08-2007) <br/> COGS = #20,000 + #140,000 - #10,000 <br/> COGS = #150,000 <br/>  <br/> Calculate the Gross Profit: <br/> Gross Profit = Sales - COGS <br/> Gross Profit = #200,000 - #150,000 <br/> Gross Profit = #50,000</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2024 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Adama Ltd on 31st August 2007 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 200000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Drawings</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Land and building</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Furniture</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\"> 50000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"> 35000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> 85000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General expenses</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock ( 31-08-2007)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 140000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-09- 2006)</td><td style=\"border:1px solid black;text-align:center;\"> 20000</td></tr></table></div> <br/> The current ratio is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1: 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate Total Current Assets: <br/> Total Current Assets = Debtors + Stock + Bank <br/> Total Current Assets = #50,000 + #10,000 + #10,000 <br/> Total Current Assets = #70,000 <br/>  <br/> Calculate the Current Ratio (assuming #35,000 current liabilities): <br/> Current Ratio = Total Current Assets / Current Liabilities <br/> Current Ratio = #70,000 / #35,000 <br/> Current Ratio = 2/1 <br/> = 2: 1</div>", "topic": "ACCOUNTING RATIO :PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2024 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In government accounting, money allocated to each head and sub- heads is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imprest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">float</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vote</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In government budgeting, funds are authorized for spending through a voting process. Each government department or agency submits a budget request, which is then debated and approved (or voted on) by the legislature. The approved amounts for each department's programs and activities become the official votes that they can spend from.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2024 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Goods bought on credit are first entered in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">journal proper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchases day book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales day book</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purchases day book is a subsidiary book specifically designed to record all credit purchases made by a company. It chronologically logs details like the date, supplier name, invoice number, description of goods, and amount of the purchase. This information is then summarized and posted to the purchases account in the general ledger at the end of the accounting period.</div>", "topic": "SUBSIDIARY BOOKS : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2024 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following accounts have debit balances except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rents and rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">return inwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">share premium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Share premium is different. When a company issues shares at a price exceeding their par value, the excess amount is recorded as a credit balance in the share premium account. It represents additional capital received from shareholders beyond the face value of the shares.</div>", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE"}, {"id": "objective>Accounts>2024 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An amount paid in cash to John is Dr to John and Cr to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dr to John: This signifies an increase in John's account balance. John could be an owner, an employee, or another type of payee. <br/>  <br/> Cr to Cash: This indicates a decrease in the cash account balance since cash is being paid out. <br/> While John's account has a debit balance because it increases his receivables, the cash account is credited because cash is leaving the business.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2024 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term \"set off\" in control account is also called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bad debt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brought forward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contra entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct transfer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This refers to a single journal entry that records a transaction affecting two accounts with opposite balances. In control accounts, a \"set off\" achieves this by using a contra entry to reconcile the balances between a control account and its corresponding subsidiary ledger (e.g., sales ledger control account vs. individual customer accounts).</div>", "topic": "CONTROL ACCOUNTS : TREATMENT OF CONTRA ENTRIES"}, {"id": "objective>Accounts>2024 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pending the location of an error, the difference in the Trial Balance is posted to a ........... account</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss appropriation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suspense</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a trial balance doesn't balance (meaning the total debits don't equal the total credits), there's an error somewhere in the accounting records. Until the error is identified and corrected, accountants use a suspense account to temporarily hold the difference.</div>", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT"}, {"id": "objective>Accounts>2024 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following balances were extracted from the books of Onuoha, a trader on 31st December 2005 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Audit fee</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General Expenses</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Commission paid</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-01-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (31-12-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 15000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr></table></div> <br/>  <br/> The gross profit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#35,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#45,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#55,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the Cost of Goods Sold (COGS): <br/> COGS = Opening Stock (1-01-2005) + Purchases - Closing Stock (31-12-2005) <br/> COGS = #10,000 + #70,000 - #15,000 <br/> COGS = #65,000 <br/>  <br/> Calculate the Gross Profit: <br/> Gross Profit = Sales - COGS <br/> Gross Profit = #120,000 - #65,000 <br/> Gross Profit = #55,000</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2024 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Onuoha, a trader on 31st December 2005 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Audit fee</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General Expenses</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Commission paid</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-01-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (31-12-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 15000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr></table></div> <br/> Goods available for sales is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#60,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#70,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#80,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#90,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Goods available for sale = Opening Stock (1-01-2005) + Purchases <br/>  <br/> Goods available for sale = #10,000 + #70,000 <br/>  <br/> = #80,000</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2024 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Onuoha, a trader on 31st December 2005 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Audit fee</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General Expenses</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Commission paid</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-01-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (31-12-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 15000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr></table></div> <br/> The cost of goods sold amounts to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#45,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#55,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#65,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#75,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">COGS = Opening Stock (1-01-2005) + Purchases - Closing Stock (31-12-2005) <br/>  <br/> COGS = #10,000 + #70,000 - #15,000 <br/>  <br/> COGS = #65,000</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2024 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The following balances were extracted from the books of Onuoha, a trader on 31st December 2005 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Audit fee</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General Expenses</td><td style=\"border:1px solid black;text-align:center;\"> 30000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 70000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Commission paid</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (1-01-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 10000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock (31-12-2005)</td><td style=\"border:1px solid black;text-align:center;\"> 15000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr></table></div> <br/> The net profit equals </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#10,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#20,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#30,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#40,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">COGS = #10,000 (Opening Stock) + #70,000 (Purchases) - #15,000 (Closing Stock) <br/> COGS = #65,000 <br/>  <br/> Calculate the Gross Profit: <br/> Gross Profit = Sales - COGS <br/> Gross Profit = #120,000 (Sales) - #65,000 (COGS) <br/> Gross Profit = #55,000 <br/>  <br/> Calculate the Net Profit: <br/> Net Profit = Gross Profit - Operating Expenses <br/> Net Profit = #55,000 (Gross Profit) - (#12,000 + #30,000 + #3,000) <br/>  <br/> Net Profit = #55,000 - #45,000 <br/>  <br/> Net Profit = #10,000</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2024 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are causes of discrepancies between the cash book and the bank statement balances except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bank charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank deposit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">errors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standing order</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> A bank deposit typically wouldn't cause a discrepancy; rather, it would lead to an increase in both the cash book and bank statement balances. Therefore, it is not a cause of discrepancies between the two balances.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}];
